const mockTickets = [
  { ticket_id: 'PROJ-101', title: 'Optimize OAuth handshake latency', description: 'Users on mobile devices experience a 2-3 second delay during the OAuth login flow. Investigation points to redundant token validation calls.', status: 'Done', url: 'https://demo.atlassian.net/browse/PROJ-101' },
  { ticket_id: 'PROJ-102', title: 'Fix payment gateway timeout on checkout', description: 'Stripe webhook occasionally times out after 30 seconds during high traffic.', status: 'Done', url: 'https://demo.atlassian.net/browse/PROJ-102' },
  { ticket_id: 'PROJ-103', title: 'Dashboard charts not rendering on Safari', description: 'Chart.js graphs fail to render on Safari 16 and below due to a missing polyfill for ResizeObserver.', status: 'In Progress', url: 'https://demo.atlassian.net/browse/PROJ-103' },
  { ticket_id: 'PROJ-104', title: 'Add dark mode support to settings page', description: 'Implement CSS variables and a theme toggle in user preferences.', status: 'To Do', url: 'https://demo.atlassian.net/browse/PROJ-104' },
  { ticket_id: 'PROJ-105', title: 'Email notifications not sending for new signups', description: 'SendGrid integration stopped delivering welcome emails after the SMTP config migration.', status: 'Done', url: 'https://demo.atlassian.net/browse/PROJ-105' },
  { ticket_id: 'PROJ-106', title: 'User profile images not loading after CDN change', description: 'After migrating to CloudFront, avatar images return 403 errors due to missing bucket policy.', status: 'Done', url: 'https://demo.atlassian.net/browse/PROJ-106' },
  { ticket_id: 'PROJ-107', title: 'Refactor database connection pooling', description: 'Current pg pool exhausts under load with 100+ concurrent users. Migrate to PgBouncer.', status: 'In Progress', url: 'https://demo.atlassian.net/browse/PROJ-107' },
  { ticket_id: 'PROJ-108', title: 'API rate limiting returns wrong HTTP status', description: 'Rate limiter returns 500 instead of 429 when quota is exceeded.', status: 'Done', url: 'https://demo.atlassian.net/browse/PROJ-108' },
  { ticket_id: 'PROJ-109', title: 'Search results missing recently created records', description: 'Elasticsearch index has a 5-minute lag due to refresh interval setting.', status: 'To Do', url: 'https://demo.atlassian.net/browse/PROJ-109' },
  { ticket_id: 'PROJ-110', title: 'Two-factor authentication codes expiring too fast', description: 'TOTP codes expire in 15 seconds instead of standard 30-second window due to server clock drift.', status: 'Done', url: 'https://demo.atlassian.net/browse/PROJ-110' }
];
return mockTickets.map(t => ({ json: t }));

const item = $input.first().json;
const title = item.title?.trim() || 'Untitled';
const description = item.description?.trim();

// Edge case: embed title only if no description
const embedText = description && description.length > 10
  ? `${title}. ${description}`
  : title;

return [{ json: { ...item, embed_text: embedText, has_description: !!(description && description.length > 10) } }];
